// Build a clean HTML invoice and hand it to Gotenberg as an index.html file.
// Totals are computed here so the template stays presentation-only.
const d = $json;
const items = Array.isArray(d.items) ? d.items : JSON.parse(d.items || '[]');
const cur = d.currency || 'EUR';
const money = (n) => new Intl.NumberFormat('es-ES', { style: 'currency', currency: cur }).format(n || 0);
const today = new Date().toLocaleDateString('es-ES');

let subtotal = 0;
const rows = items.map((it) => {
  const line = (Number(it.qty) || 0) * (Number(it.price) || 0);
  subtotal += line;
  return `<tr><td>${it.desc || ''}</td><td class="r">${it.qty}</td><td class="r">${money(it.price)}</td><td class="r">${money(line)}</td></tr>`;
}).join('');

const taxRate = Number(d.tax_rate) || 0;
const tax = subtotal * (taxRate / 100);
const total = subtotal + tax;

const html = `<!doctype html><html><head><meta charset="utf-8"><style>
  * { font-family: -apple-system, Segoe UI, Roboto, Arial, sans-serif; color: #1a1a2e; }
  body { margin: 40px; font-size: 13px; }
  h1 { font-size: 26px; margin: 0 0 4px; letter-spacing: .5px; }
  .muted { color: #6b7280; }
  .head { display: flex; justify-content: space-between; margin-bottom: 32px; }
  .box { background: #f8fafc; border: 1px solid #e5e7eb; border-radius: 8px; padding: 14px 16px; min-width: 240px; }
  table { width: 100%; border-collapse: collapse; margin-top: 8px; }
  th, td { padding: 9px 10px; border-bottom: 1px solid #e5e7eb; text-align: left; }
  th { background: #1a1a2e; color: #fff; font-size: 11px; text-transform: uppercase; letter-spacing: .4px; }
  td.r, th.r { text-align: right; }
  .totals { margin-top: 14px; width: 280px; margin-left: auto; }
  .totals td { border: none; padding: 4px 10px; }
  .grand { font-size: 16px; font-weight: 700; border-top: 2px solid #1a1a2e; }
  .foot { margin-top: 40px; font-size: 11px; }
</style></head><body>
  <div class="head">
    <div>
      <h1>FACTURA</h1>
      <div class="muted">Nº ${d.invoice_number} · ${today}</div>
    </div>
    <div class="box">
      <strong>${d.seller_name}</strong><br>
      <span class="muted">${d.seller_taxid}</span><br>
      <span class="muted">${d.seller_address}</span>
    </div>
  </div>
  <div class="box" style="margin-bottom:24px">
    <span class="muted">Facturar a</span><br>
    <strong>${d.client_name}</strong> · ${d.client_taxid}<br>
    <span class="muted">${d.client_email}</span>
  </div>
  <table>
    <thead><tr><th>Concepto</th><th class="r">Cant.</th><th class="r">Precio</th><th class="r">Importe</th></tr></thead>
    <tbody>${rows}</tbody>
  </table>
  <table class="totals">
    <tr><td>Subtotal</td><td class="r">${money(subtotal)}</td></tr>
    <tr><td>IVA (${taxRate}%)</td><td class="r">${money(tax)}</td></tr>
    <tr class="grand"><td>Total</td><td class="r">${money(total)}</td></tr>
  </table>
  <div class="foot muted">Gracias por su confianza. Pago a 30 días salvo acuerdo. Generado con n8n + Gotenberg.</div>
</body></html>`;

const buff = Buffer.from(html, 'utf8');
return [{
  json: {
    invoice_number: d.invoice_number,
    client_email: d.client_email,
    client_name: d.client_name,
    total: money(total)
  },
  binary: {
    index: { data: buff.toString('base64'), mimeType: 'text/html', fileName: 'index.html' }
  }
}];
